package com.travelassistant.consultation;
import static org.assertj.core.api.Assertions.assertThat;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;import com.travelassistant.consultation.ai.*;import java.util.*;import java.util.concurrent.*;import java.util.concurrent.atomic.AtomicInteger;import java.util.function.Consumer;import java.util.regex.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.*;import org.springframework.boot.webmvc.test.autoconfigure.AutoConfigureMockMvc;import org.springframework.context.annotation.*;import org.springframework.http.MediaType;import org.springframework.test.context.ActiveProfiles;import org.springframework.test.web.servlet.*;import tools.jackson.databind.*;
@SpringBootTest @AutoConfigureMockMvc @ActiveProfiles("test")class ConversationStreamLifecycleIntegrationTest{private static final AtomicInteger STREAM_CALLS=new AtomicInteger();@Autowired MockMvc mvc;@Autowired ObjectMapper mapper;@TestConfiguration static class Config{@Bean@Primary ConsultationProvider slowProvider(){return new ConsultationProvider(){public ConsultationResult answer(ConsultationPrompt p){return new ConsultationResult("ok","slow",1,1);}public ConsultationResult stream(ConsultationPrompt p,Consumer<String>chunks,CancellationToken token){STREAM_CALLS.incrementAndGet();int i=0;while(!token.isCancelled()){chunks.accept("片段"+(i++));try{Thread.sleep(25);}catch(InterruptedException e){Thread.currentThread().interrupt();break;}}throw new ConsultationException(token.reason(),"cancelled",false);}public String providerName(){return"slow";}public String modelName(){return"slow";}};}}
 @Test void explicitCancelPersistsCancelledTerminalWithoutProducerOverwrite()throws Exception{Context c=context("cancel-stream-01");String stream=awaitStreamId(c.started);mvc.perform(delete("/api/v1/conversations/{id}/streams/{stream}",c.conversation,stream).header("Authorization",bearer(c.token))).andExpect(status().isNoContent());mvc.perform(asyncDispatch(c.started)).andExpect(status().isOk());mvc.perform(get("/api/v1/conversations/{id}",c.conversation).header("Authorization",bearer(c.token))).andExpect(status().isOk()).andExpect(jsonPath("$.data.messages[1].status").value("FAILED")).andExpect(jsonPath("$.data.messages[1].errorCode").value("CLIENT_CANCELLED"));}
 @Test void simultaneousIdempotentPostsAtomicallyReuseOneStreamAndOneProviderCall()throws Exception{STREAM_CALLS.set(0);String token=register();String conversation=json(mvc.perform(post("/api/v1/conversations").header("Authorization",bearer(token)).contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isCreated()).andReturn()).at("/data/id").asText();CountDownLatch start=new CountDownLatch(1);ExecutorService pool=Executors.newFixedThreadPool(2);Callable<MvcResult>post=()->{start.await();return mvc.perform(post("/api/v1/conversations/{id}/messages:stream",conversation).header("Authorization",bearer(token)).header("Idempotency-Key","simultaneous-key").contentType(MediaType.APPLICATION_JSON).accept(MediaType.TEXT_EVENT_STREAM).content("{\"content\":\"慢速问题\"}")).andExpect(request().asyncStarted()).andReturn();};Future<MvcResult>one=pool.submit(post),two=pool.submit(post);start.countDown();MvcResult first=one.get(5,TimeUnit.SECONDS),second=two.get(5,TimeUnit.SECONDS);String stream=awaitStreamId(first);Thread.sleep(100);assertThat(STREAM_CALLS.get()).isEqualTo(1);mvc.perform(delete("/api/v1/conversations/{id}/streams/{stream}",conversation,stream).header("Authorization",bearer(token))).andExpect(status().isNoContent());mvc.perform(asyncDispatch(first));mvc.perform(asyncDispatch(second));pool.shutdownNow();}
 private Context context(String key)throws Exception{String token=register();String id=json(mvc.perform(post("/api/v1/conversations").header("Authorization",bearer(token)).contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isCreated()).andReturn()).at("/data/id").asText();MvcResult started=mvc.perform(post("/api/v1/conversations/{id}/messages:stream",id).header("Authorization",bearer(token)).header("Idempotency-Key",key).contentType(MediaType.APPLICATION_JSON).accept(MediaType.TEXT_EVENT_STREAM).content("{\"content\":\"慢速问题\"}")).andExpect(request().asyncStarted()).andExpect(header().exists("X-Stream-Id")).andReturn();return new Context(token,id,started);}private String awaitStreamId(MvcResult started)throws Exception{for(int i=0;i<100;i++){Matcher m=Pattern.compile("\\\"streamId\\\":\\\"([^\\\"]+)").matcher(started.getResponse().getContentAsString());if(m.find())return m.group(1);Thread.sleep(10);}throw new AssertionError("no stream id");}private String register()throws Exception{MvcResult r=mvc.perform(post("/api/v1/auth/register").contentType(MediaType.APPLICATION_JSON).content("{\"email\":\"cancel-"+UUID.randomUUID()+"@example.com\",\"password\":\"secure-pass-123\",\"displayName\":\"User\"}")).andExpect(status().isCreated()).andReturn();return json(r).at("/data/accessToken").asText();}private JsonNode json(MvcResult r)throws Exception{return mapper.readTree(r.getResponse().getContentAsString());}private String bearer(String t){return"Bearer "+t;}private record Context(String token,String conversation,MvcResult started){}}
